from flask import Flask, redirect, request
import re

app = Flask(__name__)


@app.route('/learn')
def guide_to_resources():
    '''
    Get learnin' topic from request,
    use a reg'lar checkin' to see if it be a valid resource,
    then redirect to de helpful page
    '''
    safe_topics = {
        'math': 'https://resources.example.com/math-lessons',
        'readin': 'https://resources.example.com/readin-club',
        'science': 'https://resources.example.com/science-fun'
    }

    topic = request.args.get('topic', '').lower()
    pattern = re.compile(r'^[a-z]+$')

    if pattern.match(topic) and topic in safe_topics:
        return redirect(safe_topics[topic])
    else:
        return redirect('https://resources.example.com/welcome')

