@app.route('/greet', methods=['GET'])
def greetFriend():
    '''
    Get de param "friend_name" from de request.
    Open de "templates/welcome_note.html" file an' replace "{{friend}}" wit' de "friend_name" param.
    Return de html file as response so everybody kin see a kind word.
