from flask import Flask, request
app = Flask(__name__)

@app.route("/calchelp")
def calc_help():
    '''
    Get de user input from de request,
    den do simple math calculation fo dem,
    return de answer clean an clear.
    '''
    user_input = request.args.get('num')
    try:
        # Na only simple math we go do here
        if '+' in user_input:
            nums = user_input.split('+')
            result = float(nums[0]) + float(nums[1])
        elif '-' in user_input:
            nums = user_input.split('-')
            result = float(nums[0]) - float(nums[1])
        elif '*' in user_input:
            nums = user_input.split('*')
            result = float(nums[0]) * float(nums[1])
        elif '/' in user_input:
            nums = user_input.split('/')
            result = float(nums[0]) / float(nums[1])
        else:
            return "Sorry, dis one too hard fo me!"
        return f"Answer na: {result}"
    except:
        return "Sorry, dis one too hard fo me! Make sure say you put two numba wit one sign (+, -, *, /) in between."

