from flask import Flask, request, make_response
app = Flask(__name__)

@app.route("/submit_name")
def save_user_name():
    '''
    Get "first_name" from de form wey user send, check if e be string,
    clean am proper, den save am for we database.
    Den send back one nice JSON response sayin "Name don save, tank ya!"
    '''
    first_name = request.form.get("first_name")
    if not isinstance(first_name, str):
        return make_response(json.dumps({"error": "Na string wey we need ya"}), 400)

    clean_name = first_name.strip()
