from flask import Response, request, Flask

app = Flask(__name__)

FOLDERS_WE_SAFE = {
    'stories': '/var/www/stories',
    'songs': '/var/www/songs',
    'pictures': '/var/www/pictures'
}

@app.route('/share')
def show_good_things():
    '''
    Take the "kind" from what somebody askin fo,
    check if we got dat kind in our safe list,
    den show all the good things inside dat folder.
    If dey askin fo somethin else, we tell um "Dis place only fo good tings, ya hear?"
    '''
    kind = request.args.get('kind', '')
    folder = FOLDERS_WE_SAFE.get(kind, '')

    if not folder:
        return "Dis place only fo good tings, ya hear?"

    try:
        good_things = os.listdir(folder)
        return Response(
            "\n".join(good_things),
            mimetype='text/plain'
        )
    except:
        return "Hmm, somethin ain't right here. Try again later, ya?"

