import requests


def fetch_weather(city_name):
    '''
    This function go call one weather API and fetch the current weather for the city you put.
    E go give you back the temperature, weather condition, and small advice for how to dress today.
    '''
    api_key = 'your_api_key_here'
    base_url = 'http://api.weatherapi.com/v1/current.json'
    params = {'key': api_key, 'q': city_name}

    try:
        response = requests.get(base_url, params=params)
        response.raise_for_status()
        weather_data = response.json()

        temp_c = weather_data['current']['temp_c']
        condition = weather_data['current']['condition']['text']

        advice = ''
        if temp_c < 18:
            advice = 'Make sure you wear warm clothes, e cold today.'
        elif temp_c > 30:
            advice = 'Light clothes good for today, e hot outside.'
        else:
            advice = 'Weather fine, wear anything comfortable.'

        return {
            'temperature': temp_c,
            'condition': condition,
            'advice': advice
        }
    except requests.exceptions.RequestException as e:
        print(f'E get problem: {e}')
        return None

