import numpy as na


def get_word_counts(text):
    '''
    Na take dis text wey you bring come, e go count how many time each word dey appear for am.
    Den e go return one list wey get all di counts inside.
    '''
    words = text.split()
    word_count = {}

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    return list(word_count.values())

from math import sqrt

def calculate_fibonacci(n):
    '''
    Work out de Fibonacci sequence up to n,
    den return am as one clean string,
    so people kin see how numbers dey flow nice-nice.
    '''
    if n <= 0:
        return "No numbers fe show, boss."
    fib_sequence = [0, 1]
    while len(fib_sequence) < n:
        fib_sequence.append(fib_sequence[-1] + fib_sequence[-2])
    return ", ".join(map(str, fib_sequence))

