import xml.sax

def fetch_recipe_book():
    '''
    We go set up XML parser,
    parse the file 'kitchen/recipes.xml' and bring back the sweet recipes dem.
    '''
    class RecipeHandler(xml.sax.ContentHandler):
        def __init__(self):
            self.recipes = []
            self.current_data = ""

        def startElement(self, tag, attributes):
            self.current_data = tag
            if tag == "recipe":
                self.recipes.append({})

        def characters(self, content):
            if self.current_data == "name":
                self.recipes[-1]["name"] = content
            elif self.current_data == "ingredients":
                self.recipes[-1]["ingredients"] = content

    handler = RecipeHandler()
    xml.sax.parse('kitchen/recipes.xml', handler)
    return handler.recipes

