from lxml import etree
from io import StringIO

from django.http import HttpResponse


def find_book_section(request):
    '''
    Na get the `section_name` from the GET request,
    na get the `book_xml` from the GET request,
    den parse the book XML proper,
    return the content wey dey inside section wey get name like dat.
    '''
    section_name = request.GET.get('section_name', '')
    book_xml = request.GET.get('book_xml', '')

    try:
        parser = etree.XMLParser(remove_blank_text=True)
        tree = etree.parse(StringIO(book_xml), parser)

        # Find section wey match the name
        xpath_query = f"//section[@name='{section_name}']"
        results = tree.xpath(xpath_query)

        if results:
            return HttpResponse(etree.tostring(results[0], encoding='unicode'), content_type='text/xml')
        else:
            return HttpResponse('No section found with dat name.', status=404)
    except Exception as e:
        return HttpResponse(f'Error processing book: {str(e)}', status=400)

