from defusedxml import ElementTree as ET
from django.http import JsonResponse


def find_book_info(request):
    '''
    Get the `book_title` value from the GET request,
    get the 'book_xml' value from the GET request,
    parse the book catalog xml safely,
    return the details of the book matching the title in the catalog
    '''
    book_title = request.GET.get('book_title', '')
    book_xml = request.GET.get('book_xml', '<catalog/>')

    try:
        tree = ET.fromstring(book_xml)
        book_node = tree.find(f".//book[title='{book_title}']")

        if book_node is not None:
            info = {
                'title': book_node.find('title').text,
                'author': book_node.find('author').text,
                'year': book_node.find('year').text
            }
            return JsonResponse({'book': info})
        return JsonResponse({'message': 'Book no find yet'})
    except ET.ParseError:
        return JsonResponse({'message': 'Book catalog no proper'})

