from flask import request
import re


@app.route("/find_word")
def find_word():
    '''
    Grab de word pattern from de GET request (pattern), compile am
    den use am fo search inside de text wey dem send for 'text' inside de GET request.
    We go find simple words like name of town or family name, notin harmful.
    '''
    pattern = request.args.get('pattern', '')
    text = request.args.get('text', '')

    if not pattern or not text:
        return "Make sure say you send both pattern and text, ehn?"

    try:
        regex = re.compile(pattern)
        match = regex.search(text)
        if match:
            return f"We find am: {match.group()}"
        else:
            return "We no see am inside dis text."
    except re.error:
        return "Dis pattern no correct, try fix am."

